INSERT INTO CHAT_ROOM (
    ROOM_TYPE,
    ROOM_NAME
) VALUES (
    #{roomType},
    #{roomName}
)

INSERT INTO CHAT_ROOM_MEMBER (
    ROOM_ID,
    EMPLOYEE_ID
) VALUES (
    #{roomId},
    #{employeeId}
)

mapper.delete:
DELETE FROM CHAT_ROOM_MEMBER
WHERE ROOM_ID = #{roomId}
  AND EMPLOYEE_ID = #{employeeId}

mapper.select:
SELECT MAX(MESSAGE_ID)
FROM CHAT_MESSAGE
WHERE ROOM_ID = #{roomId}

SELECT LAST_READ_MESSAGE_ID
FROM CHAT_ROOM_MEMBER
WHERE ROOM_ID = #{roomId}
  AND EMPLOYEE_ID = #{employeeId}

mapper.update:
UPDATE CHAT_ROOM_MEMBER
SET LAST_READ_MESSAGE_ID = #{messageId}
WHERE ROOM_ID = #{roomId}
  AND EMPLOYEE_ID = #{employeeId}
  AND (LAST_READ_MESSAGE_ID IS NULL
       OR LAST_READ_MESSAGE_ID < #{messageId})

UPDATE CHAT_ROOM
SET ROOM_NAME = #{roomName}
WHERE ROOM_ID = #{roomId}
  AND ROOM_TYPE = 'GROUP'

mapper.select:
SELECT cm.MESSAGE_ID, cm.ROOM_ID, cm.SENDER_ID, cm.MESSAGE_TYPE, cm.CONTENT, cm.SENT_AT, DATE_FORMAT(cm.SENT_AT, '%Y-%m-%d') AS SENT_DATE_KEY, CONCAT( DATE_FORMAT(cm.SENT_AT, '%Y년 %c월 %e일 '), ELT(DAYOFWEEK(cm.SENT_AT), '일요일', '월요일', '화요일', '수요일', '목요일', '금요일', '토요일') ) AS DISPLAY_SENT_DATE, CONCAT( CASE WHEN HOUR(cm.SENT_AT) < 12 THEN '오전 ' ELSE '오후 ' END, DATE_FORMAT(cm.SENT_AT, '%h:%i') ) AS DISPLAY_SENT_TIME, ( SELECT COUNT(*) FROM CHAT_ROOM_MEMBER readMember WHERE readMember.ROOM_ID = cm.ROOM_ID AND readMember.EMPLOYEE_ID != cm.SENDER_ID AND (readMember.LAST_READ_MESSAGE_ID IS NULL OR readMember.LAST_READ_MESSAGE_ID < cm.MESSAGE_ID) ) AS UNREAD_MEMBER_COUNT, e.EMPLOYEE_NAME AS SENDER_NAME, e.PROFILE_IMG AS SENDER_PROFILE_IMG, ca.ATTACH_ID, ca.MESSAGE_ID AS ATTACH_MESSAGE_ID, ca.FILE_NAME, ca.FILE_PATH, ca.FILE_SIZE
FROM CHAT_MESSAGE cm LEFT JOIN EMPLOYEE e ON e.EMPLOYEE_ID = cm.SENDER_ID LEFT JOIN CHAT_ATTACHMENT ca ON ca.MESSAGE_ID = cm.MESSAGE_ID
WHERE cm.MESSAGE_ID = #{messageId}
